// ═══════════════════════════════════════════════════════════════
// SHADERS.JS — Custom GLSL shaders for atmosphere, lensing, etc.
// ═══════════════════════════════════════════════════════════════
'use strict';

window.SHADERS = (function(){

  // ─── ATMOSPHERE SHADER ──────────────────────────────────────
    // Physically-based Rayleigh + Mie scattering atmosphere
      const atmosphereVert = `
          varying vec3 vNormal;
              varying vec3 vWorldPos;
                  void main(){
                        vNormal = normalize(normalMatrix * normal);
                              vWorldPos = (modelMatrix * vec4(position,1.0)).xyz;
                                    gl_Position = projectionMatrix * modelViewMatrix * vec4(position,1.0);
                                        }
                                          `;

                                            const atmosphereFrag = `
                                                uniform vec3 uAtmosColor;
                                                    uniform vec3 uSunDir;
                                                        uniform float uIntensity;
                                                            uniform float uFalloff;
                                                                varying vec3 vNormal;
                                                                    varying vec3 vWorldPos;

                                                                        void main(){
                                                                              vec3 viewDir = normalize(cameraPosition - vWorldPos);
                                                                                    float rim = 1.0 - max(0.0, dot(vNormal, viewDir));
                                                                                          rim = pow(rim, uFalloff);

                                                                                                // Sun-side brightening
                                                                                                      float sunDot = max(0.0, dot(vNormal, uSunDir));
                                                                                                            float scatter = pow(rim, 1.5) * (0.5 + sunDot * 0.5);

                                                                                                                  vec3 col = uAtmosColor * scatter * uIntensity;
                                                                                                                        float alpha = scatter * 0.85;
                                                                                                                              gl_FragColor = vec4(col, alpha);
                                                                                                                                  }
                                                                                                                                    `;

                                                                                                                                      // ─── GRAVITATIONAL LENSING (Sgr A*) ─────────────────────────
                                                                                                                                        // Fake lensing effect — distorts background stars in ring pattern
                                                                                                                                          const lensVert = `
                                                                                                                                              varying vec2 vUv;
                                                                                                                                                  void main(){ vUv = uv; gl_Position = projectionMatrix * modelViewMatrix * vec4(position,1.0); }
                                                                                                                                                    `;

                                                                                                                                                      const lensFrag = `
                                                                                                                                                          uniform sampler2D uBackground;
                                                                                                                                                              uniform float uTime;
                                                                                                                                                                  uniform float uLensStrength;
                                                                                                                                                                      varying vec2 vUv;

                                                                                                                                                                          void main(){
                                                                                                                                                                                vec2 center = vec2(0.5);
                                                                                                                                                                                      vec2 delta = vUv - center;
                                                                                                                                                                                            float dist = length(delta);

                                                                                                                                                                                                  // Einstein ring distortion
                                                                                                                                                                                                        float rs = 0.08; // Schwarzschild radius in UV
                                                                                                                                                                                                              float lensed = uLensStrength * rs*rs / (dist*dist + 0.001);
                                                                                                                                                                                                                    vec2 offset = normalize(delta) * lensed;

                                                                                                                                                                                                                          // Photon capture — inside horizon is black
                                                                                                                                                                                                                                if(dist < rs * 0.5){
                                                                                                                                                                                                                                        gl_FragColor = vec4(0.0, 0.0, 0.0, 1.0);
                                                                                                                                                                                                                                                return;
                                                                                                                                                                                                                                                      }

                                                                                                                                                                                                                                                            // Accretion glow ring
                                                                                                                                                                                                                                                                  float ring = exp(-pow((dist - rs*1.5)*18.0, 2.0));
                                                                                                                                                                                                                                                                        vec3 ringCol = mix(vec3(1.0,0.4,0.05), vec3(1.0,0.8,0.3), ring) * ring * 2.5;

                                                                                                                                                                                                                                                                              // Doppler beaming — one side brighter
                                                                                                                                                                                                                                                                                    float doppler = 0.5 + 0.5*sin(atan(delta.y,delta.x) + uTime*0.8);
                                                                                                                                                                                                                                                                                          ringCol *= (0.6 + doppler * 0.8);

                                                                                                                                                                                                                                                                                                vec2 lensedUv = clamp(vUv - offset, 0.0, 1.0);
                                                                                                                                                                                                                                                                                                      vec4 bg = texture2D(uBackground, lensedUv);
                                                                                                                                                                                                                                                                                                            gl_FragColor = vec4(bg.rgb + ringCol, 1.0);
                                                                                                                                                                                                                                                                                                                }
                                                                                                                                                                                                                                                                                                                  `;

                                                                                                                                                                                                                                                                                                                    // ─── ACCRETION DISK SHADER ───────────────────────────────────
                                                                                                                                                                                                                                                                                                                      const accretionVert = `
                                                                                                                                                                                                                                                                                                                          varying vec2 vUv;
                                                                                                                                                                                                                                                                                                                              varying vec3 vPos;
                                                                                                                                                                                                                                                                                                                                  void main(){ vUv=uv; vPos=position; gl_Position=projectionMatrix*modelViewMatrix*vec4(position,1.0); }
                                                                                                                                                                                                                                                                                                                                    `;

                                                                                                                                                                                                                                                                                                                                      const accretionFrag = `
                                                                                                                                                                                                                                                                                                                                          uniform float uTime;
                                                                                                                                                                                                                                                                                                                                              uniform float uInnerR;
                                                                                                                                                                                                                                                                                                                                                  uniform float uOuterR;
                                                                                                                                                                                                                                                                                                                                                      varying vec2 vUv;
                                                                                                                                                                                                                                                                                                                                                          varying vec3 vPos;

                                                                                                                                                                                                                                                                                                                                                              float hash(float n){ return fract(sin(n)*43758.5453); }
                                                                                                                                                                                                                                                                                                                                                                  float noise(vec2 p){ vec2 i=floor(p),f=fract(p),u=f*f*(3.0-2.0*f); return mix(mix(hash(i.x+i.y*57.0),hash(i.x+1.0+i.y*57.0),u.x),mix(hash(i.x+(i.y+1.0)*57.0),hash(i.x+1.0+(i.y+1.0)*57.0),u.x),u.y); }

                                                                                                                                                                                                                                                                                                                                                                      void main(){
                                                                                                                                                                                                                                                                                                                                                                            float r = length(vPos.xz);
                                                                                                                                                                                                                                                                                                                                                                                  float angle = atan(vPos.z, vPos.x);
                                                                                                                                                                                                                                                                                                                                                                                        float normalizedR = (r - uInnerR) / (uOuterR - uInnerR);

                                                                                                                                                                                                                                                                                                                                                                                              if(normalizedR < 0.0 || normalizedR > 1.0){ discard; }

                                                                                                                                                                                                                                                                                                                                                                                                    // Keplerian rotation speed — faster near center
                                                                                                                                                                                                                                                                                                                                                                                                          float omega = 1.0 / pow(max(r, uInnerR), 1.5);
                                                                                                                                                                                                                                                                                                                                                                                                                float phase = angle - omega * uTime * 2.0;

                                                                                                                                                                                                                                                                                                                                                                                                                      // Temperature gradient — Wien's law approximation
                                                                                                                                                                                                                                                                                                                                                                                                                            float temp = pow(1.0 - normalizedR, 2.5);
                                                                                                                                                                                                                                                                                                                                                                                                                                  vec3 hotCol  = vec3(1.0, 0.95, 0.7);   // near white-hot
                                                                                                                                                                                                                                                                                                                                                                                                                                        vec3 warmCol = vec3(1.0, 0.45, 0.08);  // orange
                                                                                                                                                                                                                                                                                                                                                                                                                                              vec3 coolCol = vec3(0.6, 0.1, 0.02);   // deep red
                                                                                                                                                                                                                                                                                                                                                                                                                                                    vec3 col = mix(coolCol, mix(warmCol, hotCol, temp*temp), temp);

                                                                                                                                                                                                                                                                                                                                                                                                                                                          // Turbulent density waves
                                                                                                                                                                                                                                                                                                                                                                                                                                                                float turb = noise(vec2(phase*3.0, normalizedR*8.0) + uTime*0.1);
                                                                                                                                                                                                                                                                                                                                                                                                                                                                      float turb2 = noise(vec2(phase*7.0 + 2.3, normalizedR*14.0) - uTime*0.05);
                                                                                                                                                                                                                                                                                                                                                                                                                                                                            float density = (turb*0.6 + turb2*0.4);

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  // Vertical thickness — thicker at edges
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        float thickness = exp(-pow(vPos.y / (0.1*(1.0+normalizedR*2.0)), 2.0));
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              float alpha = density * thickness * temp * 1.8;

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    // Doppler beaming effect
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          float doppler = 0.5 + 0.5*sin(angle + uTime*0.5);
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                col *= (0.5 + doppler * 1.0);

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      gl_FragColor = vec4(col, clamp(alpha, 0.0, 1.0));
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          }
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            `;

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              // ─── SUN SURFACE SHADER ─────────────────────────────────────
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                const sunVert = `
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    varying vec2 vUv;
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        varying vec3 vNormal;
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            void main(){ vUv=uv; vNormal=normal; gl_Position=projectionMatrix*modelViewMatrix*vec4(position,1.0); }
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              `;

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                const sunFrag = `
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    uniform float uTime;
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        varying vec2 vUv;
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            varying vec3 vNormal;

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                float hash(vec2 p){ return fract(sin(dot(p,vec2(127.1,311.7)))*43758.5453); }
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    float noise(vec2 p){ vec2 i=floor(p),f=fract(p),u=f*f*(3.0-2.0*f); return mix(mix(hash(i),hash(i+vec2(1,0)),u.x),mix(hash(i+vec2(0,1)),hash(i+vec2(1,1)),u.x),u.y); }
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        float fbm(vec2 p){ float v=0.0,a=0.5; for(int i=0;i<6;i++){v+=a*noise(p);p=p*2.1+vec2(1.3,0.7);a*=0.5;} return v; }

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            void main(){
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  vec2 uv = vUv * 6.0 + vec2(uTime*0.012, uTime*0.008);
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        float n1 = fbm(uv);
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              float n2 = fbm(uv * 2.0 + vec2(n1) + uTime*0.02);
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    float n = mix(n1, n2, 0.5);

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          // Solar granulation color
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                vec3 core    = vec3(1.0,  1.0,  0.85);
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      vec3 hot     = vec3(1.0,  0.85, 0.2);
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            vec3 darker  = vec3(0.9,  0.4,  0.02);
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  vec3 sunspot = vec3(0.25, 0.1,  0.0);

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        vec3 col = mix(darker, hot, smoothstep(0.3, 0.6, n));
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              col = mix(col, core, smoothstep(0.55, 0.8, n));

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    // Sunspots — dark patches with cycle
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          float spot = fbm(vUv*3.0 + vec2(uTime*0.003));
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                float spotMask = smoothstep(0.62, 0.58, spot);
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      col = mix(col, sunspot, spotMask * 0.7);

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            // Limb darkening
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  float limb = dot(normalize(vNormal), vec3(0,0,1));
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        limb = pow(max(0.0, limb), 0.4);
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              col *= (0.5 + 0.5*limb);

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    gl_FragColor = vec4(col, 1.0);
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        }
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          `;

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            // ─── CORONA SHADER ──────────────────────────────────────────
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              const coronaFrag = `
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  uniform float uTime;
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      varying vec3 vNormal;
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          varying vec3 vWorldPos;

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              float hash(float n){ return fract(sin(n)*43758.5453); }

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  void main(){
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        vec3 viewDir = normalize(cameraPosition - vWorldPos);
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              float rim = 1.0 - max(0.0, dot(vNormal, viewDir));
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    rim = pow(rim, 2.2);

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          // Streamer bands
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                float angle = atan(vNormal.y, vNormal.x);
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      float streamer = 0.4 + 0.6*abs(sin(angle*4.0 + uTime*0.1));

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            vec3 innerCol = vec3(1.0, 0.9, 0.5);
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  vec3 outerCol = vec3(0.6, 0.3, 0.05);
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        vec3 col = mix(outerCol, innerCol, rim) * streamer;

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              gl_FragColor = vec4(col, rim * 0.55 * streamer);
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  }
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    `;

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      // ─── STAR POINT SHADER ──────────────────────────────────────
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        // Renders stars as glowing discs with color-temperature
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          const starVert = `
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              attribute float aSize;
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  attribute vec3 aColor;
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      attribute float aBrightness;
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          varying vec3 vColor;
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              varying float vBrightness;
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  void main(){
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        vColor = aColor;
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              vBrightness = aBrightness;
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    vec4 mvPos = modelViewMatrix * vec4(position, 1.0);
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          gl_PointSize = aSize * (400.0 / -mvPos.z);
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                gl_PointSize = clamp(gl_PointSize, 0.5, 8.0);
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      gl_Position = projectionMatrix * mvPos;
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          }
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            `;

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              const starFrag = `
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  varying vec3 vColor;
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      varying float vBrightness;
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          void main(){
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                vec2 uv = gl_PointCoord - 0.5;
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      float dist = length(uv);
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            if(dist > 0.5) discard;
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  float glow = exp(-dist*dist*8.0);
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        float sharp = smoothstep(0.5, 0.1, dist);
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              float brightness = glow*0.6 + sharp*0.4;
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    gl_FragColor = vec4(vColor * brightness * vBrightness, brightness);
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        }
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          `;

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            // ─── GALAXY DISK SHADER ─────────────────────────────────────
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              const galaxyVert = `
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  attribute float aSize;
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      attribute vec3 aColor;
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          attribute float aAlpha;
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              varying vec3 vColor;
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  varying float vAlpha;
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      void main(){
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            vColor=aColor; vAlpha=aAlpha;
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  vec4 mvPos=modelViewMatrix*vec4(position,1.0);
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        gl_PointSize=aSize*(800.0/-mvPos.z);
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              gl_PointSize=clamp(gl_PointSize,0.3,12.0);
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    gl_Position=projectionMatrix*mvPos;
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        }
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          `;

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            const galaxyFrag = `
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                varying vec3 vColor;
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    varying float vAlpha;
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        void main(){
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              vec2 uv=gl_PointCoord-0.5;
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    float d=length(uv);
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          if(d>0.5) discard;
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                float a=exp(-d*d*6.0)*vAlpha;
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      gl_FragColor=vec4(vColor,a);
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          }
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            `;

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              // ─── NEBULA VOLUME SHADER ────────────────────────────────────
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                const nebulaFrag = `
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    uniform float uTime;
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        uniform vec3 uColor1;
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            uniform vec3 uColor2;
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                varying vec2 vUv;

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    float hash(vec2 p){ return fract(sin(dot(p,vec2(127.1,311.7)))*43758.5453); }
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        float noise(vec2 p){ vec2 i=floor(p),f=fract(p),u=f*f*(3.0-2.0*f); return mix(mix(hash(i),hash(i+vec2(1,0)),u.x),mix(hash(i+vec2(0,1)),hash(i+vec2(1,1)),u.x),u.y); }
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            float fbm(vec2 p,int o){ float v=0.0,a=0.5; for(int i=0;i<8;i++){ if(i>=o)break; v+=a*noise(p);p=p*2.1;a*=0.5;} return v;}

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                void main(){
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      vec2 uv = vUv;
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            float n1 = fbm(uv*3.0 + uTime*0.003, 6);
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  float n2 = fbm(uv*6.0 + n1 + uTime*0.005, 5);
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        float n = mix(n1, n2, 0.45);
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              float alpha = smoothstep(0.35, 0.7, n) * 0.6;
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    vec3 col = mix(uColor1, uColor2, n);
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          gl_FragColor = vec4(col, alpha);
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              }
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                `;

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  // ─── BLACK HOLE SHADOW ───────────────────────────────────────
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    const bhFrag = `
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        uniform float uTime;
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            uniform float uRs; // Schwarzschild radius in world units
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                varying vec3 vWorldPos;
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    varying vec3 vNormal;

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        void main(){
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              vec3 viewDir = normalize(cameraPosition - vWorldPos);
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    float rim = 1.0 - max(0.0, dot(vNormal, viewDir));

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          // Pure black center
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                gl_FragColor = vec4(0.0, 0.0, 0.0, 1.0);
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    }
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      `;

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        // Factory functions
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          function makeAtmosMaterial(color, sunDir=new THREE.Vector3(1,0,0), intensity=1.2, falloff=3.5){
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              return new THREE.ShaderMaterial({
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    uniforms:{
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            uAtmosColor:{value:new THREE.Color(color)},
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    uSunDir:{value:sunDir},
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            uIntensity:{value:intensity},
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    uFalloff:{value:falloff}
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          },
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                vertexShader: atmosphereVert,
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      fragmentShader: atmosphereFrag,
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            transparent:true, side:THREE.BackSide, depthWrite:false
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                });
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  }

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    function makeSunMaterial(){
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        return new THREE.ShaderMaterial({
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              uniforms:{ uTime:{value:0} },
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    vertexShader: sunVert,
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          fragmentShader: sunFrag
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              });
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                }

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  function makeCoronaMaterial(){
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      return new THREE.ShaderMaterial({
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            uniforms:{ uTime:{value:0} },
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  vertexShader: atmosphereVert,
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        fragmentShader: coronaFrag,
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              transparent:true, side:THREE.BackSide, depthWrite:false,
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    blending:THREE.AdditiveBlending
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        });
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          }

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            function makeAccretionDisk(innerR, outerR){
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                const geo = new THREE.RingGeometry(innerR, outerR, 128, 8);
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    const mat = new THREE.ShaderMaterial({
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          uniforms:{ uTime:{value:0}, uInnerR:{value:innerR}, uOuterR:{value:outerR} },
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                vertexShader: accretionVert,
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      fragmentShader: accretionFrag,
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            transparent:true, side:THREE.DoubleSide, depthWrite:false,
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  blending:THREE.AdditiveBlending
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      });
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          return new THREE.Mesh(geo, mat);
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            }

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              function makeStarPointsMaterial(){
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  return new THREE.ShaderMaterial({
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        uniforms:{},
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              vertexShader: starVert,
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    fragmentShader: starFrag,
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          transparent:true, depthWrite:false,
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                blending:THREE.AdditiveBlending, vertexColors:true
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    });
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      }

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        function makeGalaxyMaterial(opacity=1){
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                            return new THREE.ShaderMaterial({
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  uniforms:{},
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        vertexShader: galaxyVert,
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              fragmentShader: galaxyFrag,
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                    transparent:true, depthWrite:false,
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          blending:THREE.AdditiveBlending, vertexColors:true
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              });
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                }

                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  return {
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                      makeAtmosMaterial, makeSunMaterial, makeCoronaMaterial,
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          makeAccretionDisk, makeStarPointsMaterial, makeGalaxyMaterial,
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                              // Expose raw GLSL for advanced use
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                  glsl:{ atmosphereVert, atmosphereFrag, sunVert, sunFrag,
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                             lensFrag, accretionFrag, starVert, starFrag,
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                        galaxyVert, galaxyFrag, nebulaFrag, bhFrag, coronaFrag }
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          };
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          })();
                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                                          